import{_ as d,o as e,c as r,a2 as a}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"頁面設定說明","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Page/page-settings.md","filePath":"zh-TW/Page/page-settings.md","lastUpdated":1781962217000}'),o={name:"zh-TW/Page/page-settings.md"};function h(c,t,l,n,i,s){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="頁面設定說明" tabindex="-1">頁面設定說明 <a class="header-anchor" href="#頁面設定說明" aria-label="Permalink to &quot;頁面設定說明&quot;">​</a></h1><p>頁面設定用來調整網站顯示、上傳頁預設選項、背景圖和管理端顯示效果。</p><h2 id="全域設定" tabindex="-1">全域設定 <a class="header-anchor" href="#全域設定" aria-label="Permalink to &quot;全域設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>選項</th><th>功能</th></tr></thead><tbody><tr><td>網站標題</td><td>瀏覽器分頁顯示的標題</td></tr><tr><td>網站圖示</td><td>瀏覽器分頁的小圖示位址</td></tr><tr><td>圖床名稱</td><td>前台頁面顯示的圖床名稱</td></tr><tr><td>圖床 Logo</td><td>前台頁面顯示的 Logo 圖片位址</td></tr><tr><td>Logo 跳轉連結</td><td>點擊 Logo 或頭像後開啟的連結</td></tr><tr><td>背景切換間隔</td><td>多張背景輪播的切換時間，單位毫秒；<code>60000</code> 代表 60 秒</td></tr><tr><td>背景圖透明度</td><td>背景圖透明度，範圍 <code>0</code> 到 <code>1</code>；數值越小越淡</td></tr><tr><td>預設 URL 前綴</td><td>產生圖片連結時使用的前綴；留空時使用目前站台網域</td></tr></tbody></table><h2 id="使用者端設定" tabindex="-1">使用者端設定 <a class="header-anchor" href="#使用者端設定" aria-label="Permalink to &quot;使用者端設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>選項</th><th>功能</th></tr></thead><tbody><tr><td>公告</td><td>上傳頁頂部公告內容，支援 HTML</td></tr><tr><td>預設上傳渠道</td><td>上傳頁預設選中的上傳渠道，也可以選 Smart Dispatch 自動調度</td></tr><tr><td>預設上傳目錄</td><td>上傳頁預設目錄，例如 <code>/user/</code>；留空或 <code>/</code> 代表根目錄</td></tr><tr><td>預設命名方式</td><td>上傳後檔名的預設產生方式，見下方說明</td></tr><tr><td>預設轉換 WebP</td><td>上傳前將圖片轉成 WebP</td></tr><tr><td>預設啟用壓縮</td><td>上傳前在瀏覽器本機壓縮圖片</td></tr><tr><td>預設壓縮門檻</td><td>圖片超過該大小時自動壓縮，單位 MB</td></tr><tr><td>預設目標大小</td><td>壓縮後希望接近的檔案大小，單位 MB</td></tr><tr><td>登入頁背景圖</td><td>使用者登入頁背景圖</td></tr><tr><td>上傳頁背景圖</td><td>上傳頁背景圖</td></tr><tr><td>頁尾傳送門連結</td><td>頁尾傳送門按鈕開啟的連結</td></tr><tr><td>隱藏頁尾</td><td>開啟後隱藏前台頁尾</td></tr></tbody></table><h2 id="管理端設定" tabindex="-1">管理端設定 <a class="header-anchor" href="#管理端設定" aria-label="Permalink to &quot;管理端設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>選項</th><th>功能</th></tr></thead><tbody><tr><td>管理端登入頁背景圖</td><td>管理端登入頁背景圖</td></tr><tr><td>管理端背景圖</td><td>後台頁面背景圖；可填單張圖片 URL，也可填多個 URL</td></tr><tr><td>圖片載入模式</td><td>管理端圖片列表的預覽載入方式，可選原圖或智慧載入；智慧載入會優先讓公開圖片使用縮圖，受限圖片使用原圖</td></tr><tr><td>縮圖圖源</td><td>選擇縮圖由哪個服務產生，可選 wsrv.nl、Cloudflare 圖片轉換或 WordPress Photon；選 Cloudflare 圖片轉換前，需要先在 Cloudflare 啟用圖片轉換</td></tr><tr><td>Live2D 看板娘</td><td>開啟後在管理端顯示 Live2D 看板娘</td></tr><tr><td>煙火點擊特效</td><td>開啟後點擊頁面時顯示煙火效果</td></tr><tr><td>星星拖尾特效</td><td>開啟後滑鼠移動時顯示星星拖尾效果</td></tr></tbody></table><h2 id="背景圖填寫方式" tabindex="-1">背景圖填寫方式 <a class="header-anchor" href="#背景圖填寫方式" aria-label="Permalink to &quot;背景圖填寫方式&quot;">​</a></h2><p>登入頁背景圖、上傳頁背景圖、管理端登入頁背景圖支援：</p><table tabindex="0"><thead><tr><th>寫法</th><th>效果</th></tr></thead><tbody><tr><td><code>bing</code></td><td>使用 Bing 桌布輪播</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>多張圖片輪播</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>單張背景圖</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>隨機圖 API 連結；也可以先在「其他設定」裡設定自己的隨機圖 API，再把呼叫示範產生的隨機圖連結用單張背景圖格式填到這裡</td></tr></tbody></table><p>管理端背景圖支援圖片 URL；多個 URL 可依頁面提示用英文逗號分隔。留空時使用預設背景。</p><h2 id="預設命名方式" tabindex="-1">預設命名方式 <a class="header-anchor" href="#預設命名方式" aria-label="Permalink to &quot;預設命名方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方式</th><th>產生效果</th></tr></thead><tbody><tr><td>預設</td><td>時間隨機前綴 + 原檔名，例如 <code>1760000000000_cat.png</code></td></tr><tr><td>僅前綴</td><td>只使用時間隨機前綴和副檔名，例如 <code>1760000000000.png</code></td></tr><tr><td>僅原名</td><td>保留原檔名，例如 <code>cat.png</code>；重名時自動加 <code>(1)</code>、<code>(2)</code></td></tr><tr><td>短連結</td><td>使用 8 位短 ID 和副檔名，例如 <code>a1b2c3d4.png</code></td></tr></tbody></table>',14)])])}const u=d(o,[["render",h]]);export{p as __pageData,u as default};
